import { Link } from 'react-router-dom';

function LeadTable({
  leads = [],
  onEdit,
  onDelete
}) {
  /*
    SAFETY CHECK
  */
  if (!Array.isArray(leads)) {
    return (
      <p className="empty-msg">
        Failed to load leads.
      </p>
    );
  }

  /*
    EMPTY STATE
  */
  if (leads.length === 0) {
    return (
      <p className="empty-msg">
        No leads found.
      </p>
    );
  }

  return (
    <div className="table-wrapper">
      <table className="lead-table">
        <thead>
          <tr>
            <th>Name</th>
            <th>Country</th>
            <th>Course</th>
            <th>Counselor</th>
            <th>Status</th>
            <th>Priority</th>
            <th>Actions</th>
          </tr>
        </thead>

        <tbody>
          {leads.map((lead) => (
            <tr key={lead._id}>
              {/* NAME */}
              <td>
                <Link
                  className="lead-link"
                  to={`/leads/${lead._id}`}
                >
                  {lead.fullName}
                </Link>
              </td>

              {/* COUNTRY */}
              <td>
                {lead.country || '-'}
              </td>

              {/* COURSE */}
              <td>
                {lead.courseInterested ||
                  '-'}
              </td>

              {/* COUNSELOR */}
              <td>
                {lead.assignedCounselor ||
                  'Unassigned'}
              </td>

              {/* STATUS */}
              <td>
                <span
                  className={`badge badge-${lead.leadStatus
                    ?.replace(/\s+/g, '-')
                    .toLowerCase()}`}
                >
                  {lead.leadStatus}
                </span>
              </td>

              {/* PRIORITY */}
              <td>
                <span
                  className={`priority-${lead.priority?.toLowerCase()}`}
                >
                  {lead.priority}
                </span>
              </td>

              {/* ACTIONS */}
              <td className="actions">
                <button
                  className="btn-edit"
                  onClick={() =>
                    onEdit(lead)
                  }
                >
                  Edit
                </button>

                <button
                  className="btn-delete"
                  onClick={() =>
                    onDelete(
                      lead._id
                    )
                  }
                >
                  Delete
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default LeadTable;
